/* ========================================
   SOFATELCOM - DESIGN TOKENS
   System de design cohérent et scalable
   ======================================== */

:root {
  /* ===== COLOR SYSTEM ===== */
  --color-primary: #dc3545;
  --color-primary-dark: #c02a37;
  --color-primary-light: #ff6b7a;
  --color-primary-hover: #bd2130;

  --color-secondary: #0d6efd;
  --color-secondary-dark: #0b5ed7;
  --color-secondary-light: #4d7fe8;

  --color-success: #198754;
  --color-warning: #ffc107;
  --color-danger: #dc3545;
  --color-info: #0dcaf0;

  /* Neutral Scale (Gray) */
  --color-neutral-0: #ffffff;
  --color-neutral-50: #f8f9fa;
  --color-neutral-100: #f0f1f3;
  --color-neutral-200: #e0e3e8;
  --color-neutral-300: #c1c7cd;
  --color-neutral-400: #8b92a0;
  --color-neutral-500: #5c6370;
  --color-neutral-600: #495057;
  --color-neutral-700: #343a40;
  --color-neutral-800: #1a1d21;

  /* ===== SPACING SYSTEM (8px base) ===== */
  --space-xs: 0.25rem;    /* 4px */
  --space-sm: 0.5rem;     /* 8px */
  --space-md: 1rem;       /* 16px */
  --space-lg: 1.5rem;     /* 24px */
  --space-xl: 2rem;       /* 32px */
  --space-2xl: 3rem;      /* 48px */
  --space-3xl: 4rem;      /* 64px */

  /* ===== TYPOGRAPHY ===== */
  --font-family-base: -apple-system, BlinkMacSystemFont, "Segoe UI", "Roboto", "Helvetica Neue", sans-serif;
  --font-family-mono: "SF Mono", Monaco, "Cascadia Code", "Roboto Mono", Consolas, "Courier New", monospace;

  --font-size-xs: 0.75rem;
  --font-size-sm: 0.875rem;
  --font-size-base: 1rem;
  --font-size-lg: 1.125rem;
  --font-size-xl: 1.5rem;
  --font-size-2xl: 1.875rem;
  --font-size-3xl: 2.25rem;

  --font-weight-regular: 400;
  --font-weight-medium: 500;
  --font-weight-semibold: 600;
  --font-weight-bold: 700;

  --line-height-tight: 1.2;
  --line-height-normal: 1.5;
  --line-height-relaxed: 1.75;

  /* ===== BORDER RADIUS ===== */
  --radius-xs: 0.125rem;
  --radius-sm: 0.25rem;
  --radius-md: 0.375rem;
  --radius-lg: 0.5rem;
  --radius-xl: 0.75rem;
  --radius-2xl: 1rem;
  --radius-full: 9999px;

  /* ===== SHADOWS ===== */
  --shadow-xs: 0 1px 2px 0 rgba(0, 0, 0, 0.05);
  --shadow-sm: 0 1px 2px 0 rgba(0, 0, 0, 0.05), 0 1px 3px 0 rgba(0, 0, 0, 0.1);
  --shadow-md: 0 4px 6px -1px rgba(0, 0, 0, 0.1), 0 2px 4px -1px rgba(0, 0, 0, 0.06);
  --shadow-lg: 0 10px 15px -3px rgba(0, 0, 0, 0.1), 0 4px 6px -2px rgba(0, 0, 0, 0.05);
  --shadow-xl: 0 20px 25px -5px rgba(0, 0, 0, 0.1), 0 10px 10px -5px rgba(0, 0, 0, 0.04);

  /* ===== TRANSITIONS ===== */
  --transition-fast: 150ms cubic-bezier(0.4, 0, 0.2, 1);
  --transition-base: 200ms cubic-bezier(0.4, 0, 0.2, 1);
  --transition-slow: 300ms cubic-bezier(0.4, 0, 0.2, 1);

  /* ===== Z-INDEX SCALE ===== */
  --z-dropdown: 1000;
  --z-sticky: 1020;
  --z-fixed: 1030;
  --z-modal-backdrop: 1040;
  --z-modal: 1050;
  --z-popover: 1060;
  --z-tooltip: 1070;
  --z-notification: 1080;

  /* ===== GRADIENTS ===== */
  --gradient-primary: linear-gradient(135deg, #dc3545 0%, #ff6b7a 100%);
  --gradient-secondary: linear-gradient(135deg, #0d6efd 0%, #4d7fe8 100%);
  --gradient-subtle: linear-gradient(135deg, #f8f9fa 0%, #f0f1f3 100%);
}

/* DARK MODE READY (future implementation) */
@media (prefers-color-scheme: dark) {
  :root {
    --color-neutral-0: #1a1d21;
    --color-neutral-50: #262b33;
    --color-neutral-100: #3a414d;
    --color-neutral-200: #4d5563;
    --color-neutral-500: #a1a9b3;
    --color-neutral-700: #e5e7eb;
    --color-neutral-800: #f3f4f6;
  }
}
