/* ========================================
   SOFATELCOM MODERN FORMS & INPUTS
   Enhanced form styling with accessibility
   ======================================== */

@import url('design-tokens.css');

/* ===== FORM GROUPS & LAYOUT ===== */
.form-group {
    margin-bottom: var(--space-lg);
}

.form-group:last-child {
    margin-bottom: 0;
}

/* ===== FORM ROW (Multi-column forms) ===== */
.form-row {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
    gap: var(--space-lg);
}

.form-row.two-columns {
    grid-template-columns: repeat(2, 1fr);
}

.form-row.three-columns {
    grid-template-columns: repeat(3, 1fr);
}

@media (max-width: 768px) {
    .form-row {
        grid-template-columns: 1fr;
    }

    .form-row.two-columns,
    .form-row.three-columns {
        grid-template-columns: 1fr;
    }
}

/* ===== INPUT GROUP ENHANCEMENTS ===== */
.input-group {
    border-radius: var(--radius-md);
    overflow: hidden;
}

.input-group-text {
    background-color: var(--color-neutral-100);
    border: 2px solid var(--color-neutral-200);
    border-right: none;
    color: var(--color-neutral-600);
    font-weight: var(--font-weight-medium);
    transition: border-color var(--transition-fast), background-color var(--transition-fast);
}

.input-group > .form-control {
    border-left: none;
}

.input-group > .form-control:focus ~ .input-group-text,
.input-group-text:has(~ .form-control:focus) {
    border-color: var(--color-primary);
    background-color: var(--color-neutral-0);
}

/* ===== CHECKBOX & RADIO MODERN STYLING ===== */
.form-check {
    padding: 0.75rem var(--space-md);
    border-radius: var(--radius-md);
    transition: background-color var(--transition-fast);
}

.form-check:hover {
    background-color: var(--color-neutral-50);
}

.form-check-input {
    width: 1.25rem;
    height: 1.25rem;
    margin-top: 0.25rem;
    border: 2px solid var(--color-neutral-300);
    border-radius: 0.25rem;
    cursor: pointer;
    transition: all var(--transition-fast);
    appearance: none;
    background-color: white;
    background-repeat: no-repeat;
    background-position: center;
    background-size: contain;
    flex-shrink: 0;
}

.form-check-input:hover:not(:disabled) {
    border-color: var(--color-primary);
    box-shadow: 0 0 0 2px rgba(220, 53, 69, 0.1);
}

.form-check-input:checked {
    background-color: var(--color-primary);
    border-color: var(--color-primary);
    background-image: url("data:image/svg+xml,%3csvg xmlns='http://www.w3.org/2000/svg' viewBox='0 0 20 20'%3e%3cpath fill='none' stroke='white' stroke-linecap='round' stroke-linejoin='round' stroke-width='3' d='M6 10l3 3l6-6'/%3e%3c/svg%3e");
}

.form-check-input:checked:hover:not(:disabled) {
    background-color: var(--color-primary-hover);
    border-color: var(--color-primary-hover);
}

.form-check-input:focus-visible {
    outline: 3px solid var(--color-primary);
    outline-offset: 2px;
    border-radius: 0.25rem;
}

.form-check-input:disabled {
    opacity: 0.5;
    cursor: not-allowed;
}

.form-check-label {
    cursor: pointer;
    user-select: none;
    color: var(--color-neutral-700);
    font-weight: var(--font-weight-medium);
    margin-bottom: 0;
}

/* Radio buttons */
.form-check-input[type="radio"] {
    border-radius: 50%;
}

.form-check-input[type="radio"]:checked {
    background-image: url("data:image/svg+xml,%3csvg xmlns='http://www.w3.org/2000/svg' viewBox='0 0 20 20'%3e%3ccircle r='8' cx='10' cy='10' fill='white'/%3e%3c/svg%3e");
}

/* ===== SWITCH TOGGLE ===== */
.form-switch {
    padding-left: 0;
}

.form-switch .form-check-input {
    width: 2.5rem;
    height: 1.25rem;
    border-radius: 1rem;
    background-color: var(--color-neutral-300);
    background-position: left 0.25rem center;
    background-size: 1rem 1rem;
    border: none;
    appearance: none;
    cursor: pointer;
    transition: all var(--transition-fast);
}

.form-switch .form-check-input:checked {
    background-color: var(--color-success);
    background-position: right 0.25rem center;
    background-image: url("data:image/svg+xml,%3csvg xmlns='http://www.w3.org/2000/svg' viewBox='0 0 20 20'%3e%3cpath fill='none' stroke='white' stroke-linecap='round' stroke-linejoin='round' stroke-width='3' d='M6 10l3 3l6-6'/%3e%3c/svg%3e");
}

.form-switch .form-check-input:hover:not(:disabled) {
    box-shadow: 0 0 0 3px rgba(25, 135, 84, 0.1);
}

/* ===== FILE INPUT STYLING ===== */
.form-control[type="file"] {
    padding: 0.75rem 1rem;
    cursor: pointer;
    overflow: hidden;
}

.form-control[type="file"]::file-selector-button {
    padding: 0.5rem 1rem;
    margin: -0.75rem -1rem -0.75rem -1rem;
    margin-inline-end: 1rem;
    color: white;
    background: var(--color-primary);
    border: none;
    border-radius: 0;
    font-weight: var(--font-weight-medium);
    cursor: pointer;
    transition: background-color var(--transition-fast);
}

.form-control[type="file"]::file-selector-button:hover {
    background: var(--color-primary-hover);
}

.form-control[type="file"]::-webkit-file-upload-button {
    padding: 0.5rem 1rem;
    margin: -0.75rem -1rem -0.75rem -1rem;
    margin-inline-end: 1rem;
    color: white;
    background: var(--color-primary);
    border: none;
    border-radius: 0;
    font-weight: var(--font-weight-medium);
    cursor: pointer;
    transition: background-color var(--transition-fast);
}

.form-control[type="file"]::-webkit-file-upload-button:hover {
    background: var(--color-primary-hover);
}

/* ===== TEXTAREA ENHANCEMENTS ===== */
textarea.form-control {
    resize: vertical;
    min-height: 100px;
    font-family: var(--font-family-mono);
    font-size: var(--font-size-sm);
}

textarea.form-control:focus {
    resize: both;
}

/* ===== COLOR INPUT ===== */
.form-control[type="color"] {
    height: 3rem;
    padding: 0.375rem;
    cursor: pointer;
}

/* ===== RANGE SLIDER ===== */
.form-range {
    height: 0.5rem;
}

.form-range .form-range-track {
    background-color: var(--color-neutral-200);
    border-radius: var(--radius-full);
}

.form-range .form-range-thumb {
    width: 1.5rem;
    height: 1.5rem;
    background-color: var(--color-primary);
    border: 3px solid white;
    box-shadow: var(--shadow-md);
    cursor: pointer;
    transition: all var(--transition-fast);
}

.form-range .form-range-thumb:hover {
    box-shadow: 0 0 0 3px rgba(220, 53, 69, 0.15), var(--shadow-lg);
    transform: scale(1.1);
}

/* ===== FORM VALIDATION MESSAGES ===== */
.valid-feedback,
.invalid-feedback {
    display: none;
    font-size: var(--font-size-sm);
    font-weight: var(--font-weight-medium);
    margin-top: 0.5rem;
    animation: slideDown var(--transition-fast);
}

.form-control.is-valid ~ .valid-feedback {
    display: block;
    color: var(--color-success);
}

.form-control.is-invalid ~ .invalid-feedback {
    display: block;
    color: var(--color-danger);
}

.was-validated .form-control:valid {
    border-color: var(--color-success);
}

.was-validated .form-control:valid:focus {
    border-color: var(--color-success);
    box-shadow: 0 0 0 3px rgba(25, 135, 84, 0.1);
}

.was-validated .form-control:invalid {
    border-color: var(--color-danger);
}

.was-validated .form-control:invalid:focus {
    border-color: var(--color-danger);
    box-shadow: 0 0 0 3px rgba(220, 53, 69, 0.1);
}

/* ===== FLOATING LABELS ===== */
.form-floating > .form-control {
    border-radius: var(--radius-md);
}

.form-floating > .form-control:focus,
.form-floating > .form-control:not(:placeholder-shown) {
    padding-top: 1.625rem;
    padding-bottom: 0.625rem;
}

.form-floating > label {
    color: var(--color-neutral-600);
    padding: 1rem 0.75rem;
    transition: all var(--transition-fast);
}

.form-floating > .form-control:focus ~ label,
.form-floating > .form-control:not(:placeholder-shown) ~ label {
    opacity: 0.65;
    transform: scale(0.85) translateY(-0.5rem) translateX(0.15rem);
    color: var(--color-primary);
}

/* ===== FORM SECTION HEADERS ===== */
.form-section {
    margin-bottom: var(--space-xl);
    padding-bottom: var(--space-xl);
    border-bottom: 1px solid var(--color-neutral-200);
}

.form-section:last-child {
    margin-bottom: 0;
    padding-bottom: 0;
    border-bottom: none;
}

.form-section-title {
    font-size: var(--font-size-lg);
    font-weight: var(--font-weight-semibold);
    color: var(--color-neutral-900);
    margin-bottom: var(--space-md);
    display: flex;
    align-items: center;
    gap: var(--space-md);
}

.form-section-subtitle {
    font-size: var(--font-size-sm);
    color: var(--color-neutral-500);
    margin-bottom: var(--space-md);
}

/* ===== REQUIRED FIELD INDICATOR ===== */
.required::after {
    content: " *";
    color: var(--color-danger);
    font-weight: var(--font-weight-bold);
}

/* ===== FORM ACTIONS (Button bar) ===== */
.form-actions {
    display: flex;
    gap: var(--space-md);
    justify-content: flex-end;
    margin-top: var(--space-xl);
    padding-top: var(--space-xl);
    border-top: 1px solid var(--color-neutral-200);
}

.form-actions.center {
    justify-content: center;
}

.form-actions.start {
    justify-content: flex-start;
}

@media (max-width: 576px) {
    .form-actions {
        flex-direction: column;
        gap: var(--space-md);
    }

    .form-actions .btn {
        width: 100%;
    }
}

/* ===== HELP TEXT & HINTS ===== */
.form-text {
    font-size: var(--font-size-sm);
    color: var(--color-neutral-500);
    margin-top: 0.5rem;
    line-height: var(--line-height-relaxed);
}

.form-text.muted {
    opacity: 0.75;
}

/* ===== FIELDSET STYLING ===== */
fieldset {
    border: 1px solid var(--color-neutral-200);
    border-radius: var(--radius-lg);
    padding: var(--space-lg);
    margin-bottom: var(--space-lg);
}

legend {
    padding: 0 var(--space-md);
    font-size: var(--font-size-lg);
    font-weight: var(--font-weight-semibold);
    color: var(--color-neutral-900);
}

/* ===== DISABLED STATE ===== */
.form-control:disabled,
.form-control[readonly] {
    background-color: var(--color-neutral-100);
    color: var(--color-neutral-400);
    cursor: not-allowed;
    opacity: 0.75;
    border-color: var(--color-neutral-200);
}

/* ===== FORM LOADING STATE ===== */
.form-loading {
    pointer-events: none;
    opacity: 0.6;
}

.form-loading::after {
    content: "";
    position: fixed;
    top: 0;
    left: 0;
    right: 0;
    bottom: 0;
    background: rgba(0, 0, 0, 0.3);
    display: flex;
    align-items: center;
    justify-content: center;
    z-index: 9999;
}

/* ===== RESPONSIVE FORMS ===== */
@media (max-width: 768px) {
    .form-group {
        margin-bottom: var(--space-md);
    }

    .form-label {
        font-size: var(--font-size-sm);
    }

    .form-control {
        font-size: 16px;
    }

    .form-section {
        padding-bottom: var(--space-lg);
    }
}

/* ===== ANIMATION FOR VALIDATION ===== */
@keyframes slideDown {
    from {
        opacity: 0;
        transform: translateY(-4px);
    }
    to {
        opacity: 1;
        transform: translateY(0);
    }
}

@keyframes shake {
    0%, 100% { transform: translateX(0); }
    10%, 30%, 50%, 70%, 90% { transform: translateX(-5px); }
    20%, 40%, 60%, 80% { transform: translateX(5px); }
}

.form-control.invalid-animate {
    animation: shake 0.5s;
}
