/* ========================================
   SOFATELCOM MICRO-INTERACTIONS
   Subtle animations and transitions
   ======================================== */

@import url('design-tokens.css');

/* ===== BUTTON INTERACTIONS ===== */
.btn {
    position: relative;
    overflow: hidden;
}

/* Ripple effect for buttons */
.btn::before {
    content: '';
    position: absolute;
    top: 50%;
    left: 50%;
    width: 0;
    height: 0;
    border-radius: 50%;
    background: rgba(255, 255, 255, 0.5);
    transform: translate(-50%, -50%);
    opacity: 0;
}

.btn:active::before {
    animation: ripple 0.6s ease-out;
}

@keyframes ripple {
    from {
        width: 0;
        height: 0;
        opacity: 1;
    }
    to {
        width: 100%;
        height: 100%;
        opacity: 0;
    }
}

/* Button scale on hover */
.btn:not(:disabled):hover {
    animation: buttonHover 0.3s ease-out forwards;
}

@keyframes buttonHover {
    to {
        transform: translateY(-2px);
    }
}

.btn:active:not(:disabled) {
    animation: buttonActive 0.1s ease-out forwards;
}

@keyframes buttonActive {
    to {
        transform: translateY(0);
    }
}

/* ===== CARD INTERACTIONS ===== */
.card {
    position: relative;
}

.card::after {
    content: '';
    position: absolute;
    top: 0;
    left: 0;
    right: 0;
    bottom: 0;
    background: linear-gradient(135deg, transparent 0%, rgba(220, 53, 69, 0.05) 100%);
    opacity: 0;
    border-radius: var(--radius-lg);
    pointer-events: none;
    transition: opacity var(--transition-base);
}

.card:hover::after {
    opacity: 1;
}

/* Stat card pulse on hover */
.stat-card:hover {
    animation: cardPulse 0.4s ease-out;
}

@keyframes cardPulse {
    0% { transform: translateY(-4px); }
    50% { transform: translateY(-6px); }
    100% { transform: translateY(-4px); }
}

/* ===== INPUT INTERACTIONS ===== */
.form-control {
    position: relative;
}

/* Focus ring animation */
.form-control:focus {
    animation: focusRing 0.3s ease-out;
}

@keyframes focusRing {
    from {
        box-shadow: inset 0 0 0 0 rgba(220, 53, 69, 0.1), 0 0 0 3px rgba(220, 53, 69, 0);
    }
    to {
        box-shadow: inset 0 0 0 0 rgba(220, 53, 69, 0), 0 0 0 3px rgba(220, 53, 69, 0.1);
    }
}

/* Floating label animation */
.form-floating > .form-control:focus ~ label,
.form-floating > .form-control:not(:placeholder-shown) ~ label {
    animation: floatLabel 0.3s ease-out forwards;
}

@keyframes floatLabel {
    from {
        transform: translateY(0);
        opacity: 1;
    }
    to {
        transform: scale(0.85) translateY(-0.5rem) translateX(0.15rem);
        opacity: 0.65;
    }
}

/* ===== LINK INTERACTIONS ===== */
a:not(.btn):not(.nav-link):not(.dropdown-item) {
    position: relative;
    transition: color var(--transition-fast);
}

a:not(.btn):not(.nav-link):not(.dropdown-item)::after {
    content: '';
    position: absolute;
    bottom: -2px;
    left: 0;
    width: 0;
    height: 2px;
    background: currentColor;
    transition: width var(--transition-fast);
}

a:not(.btn):not(.nav-link):not(.dropdown-item):hover::after {
    width: 100%;
}

/* ===== DROPDOWN ANIMATIONS ===== */
.dropdown-menu {
    animation: dropdownFade 0.2s ease-out;
    transform-origin: top;
}

@keyframes dropdownFade {
    from {
        opacity: 0;
        transform: translateY(-10px);
    }
    to {
        opacity: 1;
        transform: translateY(0);
    }
}

.dropdown-item {
    position: relative;
    transition: padding-left var(--transition-fast), background-color var(--transition-fast);
}

.dropdown-item:hover {
    padding-left: calc(1.5rem + 4px);
    animation: dropdownItemSlide 0.2s ease-out;
}

@keyframes dropdownItemSlide {
    from {
        transform: translateX(-4px);
    }
    to {
        transform: translateX(0);
    }
}

/* ===== MODAL ANIMATIONS ===== */
.modal.fade .modal-dialog {
    transition: transform var(--transition-base) cubic-bezier(0.4, 0, 0.2, 1);
    transform: translateY(50px);
    opacity: 0;
}

.modal.show .modal-dialog {
    transform: translateY(0);
    opacity: 1;
}

/* ===== BADGE & PILL ANIMATIONS ===== */
.badge {
    animation: badgeIn 0.3s ease-out;
}

@keyframes badgeIn {
    from {
        transform: scale(0.8);
        opacity: 0;
    }
    to {
        transform: scale(1);
        opacity: 1;
    }
}

/* ===== NOTIFICATION ANIMATIONS ===== */
.alert {
    animation: slideInAlert 0.3s cubic-bezier(0.4, 0, 0.2, 1);
}

@keyframes slideInAlert {
    from {
        opacity: 0;
        transform: translateY(-20px);
    }
    to {
        opacity: 1;
        transform: translateY(0);
    }
}

/* ===== TABLE ROW HOVER ===== */
.table-hover tbody tr {
    transition: background-color var(--transition-fast);
}

.table-hover tbody tr:hover {
    animation: tableRowHover 0.2s ease-out;
}

@keyframes tableRowHover {
    from {
        background-color: transparent;
    }
    to {
        background-color: var(--color-neutral-50);
    }
}

/* ===== LOADING STATE ANIMATIONS ===== */
.spinner-border {
    animation: spinner-border 0.75s linear infinite;
}

@keyframes spinner-border {
    to { transform: rotate(360deg); }
}

.spinner-grow {
    animation: spinner-grow 0.75s infinite;
}

@keyframes spinner-grow {
    0%, 100% { transform: scale(0); opacity: 0; }
    50% { transform: scale(1); opacity: 1; }
}

/* ===== PAGE TRANSITION ===== */
@supports (animation-timeline: view()) {
    .page-enter {
        animation: pageEnter 0.4s ease-out;
    }

    @keyframes pageEnter {
        from {
            opacity: 0;
            transform: translateY(20px);
        }
        to {
            opacity: 1;
            transform: translateY(0);
        }
    }
}

/* ===== SCROLL REVEAL ANIMATIONS ===== */
.scroll-reveal {
    opacity: 0;
    transform: translateY(20px);
    animation: scrollReveal 0.6s ease-out forwards;
}

@keyframes scrollReveal {
    to {
        opacity: 1;
        transform: translateY(0);
    }
}

/* Stagger animation for lists */
.scroll-reveal:nth-child(1) { animation-delay: 0.05s; }
.scroll-reveal:nth-child(2) { animation-delay: 0.1s; }
.scroll-reveal:nth-child(3) { animation-delay: 0.15s; }
.scroll-reveal:nth-child(4) { animation-delay: 0.2s; }
.scroll-reveal:nth-child(n+5) { animation-delay: 0.25s; }

/* ===== ATTENTION SEEKERS ===== */
.pulse {
    animation: pulse 2s cubic-bezier(0.4, 0, 0.6, 1) infinite;
}

@keyframes pulse {
    0%, 100% { opacity: 1; }
    50% { opacity: 0.5; }
}

.bounce {
    animation: bounce 1s infinite;
}

@keyframes bounce {
    0%, 100% { transform: translateY(0); }
    50% { transform: translateY(-10px); }
}

.wiggle {
    animation: wiggle 0.5s ease-in-out;
}

@keyframes wiggle {
    0%, 100% { transform: rotateZ(0deg); }
    25% { transform: rotateZ(-2deg); }
    75% { transform: rotateZ(2deg); }
}

/* ===== DISABLE ANIMATIONS IF PREFERS REDUCED MOTION ===== */
@media (prefers-reduced-motion: reduce) {
    *,
    *::before,
    *::after {
        animation-duration: 0.01ms !important;
        animation-iteration-count: 1 !important;
        transition-duration: 0.01ms !important;
        scroll-behavior: auto !important;
    }
}

/* ===== DARK MODE TRANSITIONS ===== */
@media (prefers-color-scheme: dark) {
    body {
        background-color: #0f172a;
        color: #e2e8f0;
    }

    .card {
        background-color: #1e293b;
        border-color: #334155;
    }

    .form-control {
        background-color: #1e293b;
        color: #e2e8f0;
        border-color: #334155;
    }

    .form-control:focus {
        background-color: #0f172a;
        border-color: #dc3545;
    }
}

/* ===== INTERACTIVE STATES ===== */
[role="button"],
.btn,
a,
input,
select,
textarea {
    transition: all var(--transition-fast);
}

/* Focus-visible polyfill for older browsers */
.js-focus-visible :focus:not(.focus-visible) {
    outline: none;
}

/* ===== SMOOTH SCROLL ===== */
html {
    scroll-behavior: smooth;
}

/* ===== COLOR TRANSITION ===== */
.bg-primary,
.bg-secondary,
.bg-success,
.bg-warning,
.bg-danger,
.bg-info,
.bg-light,
.bg-dark {
    transition: background-color var(--transition-base);
}

/* ===== TRANSFORM PERFORMANCE ===== */
.will-change {
    will-change: transform;
}

/* ===== TRANSFORM ORIGIN ===== */
.transform-origin-center { transform-origin: center; }
.transform-origin-top { transform-origin: top; }
.transform-origin-bottom { transform-origin: bottom; }
.transform-origin-left { transform-origin: left; }
.transform-origin-right { transform-origin: right; }
