/* ============================================================================
   Mobile-first Navigation & Layout Overrides for Sofatelcom WebView
   Purpose: Drawer-based navigation, improved touch targets, optimized for small screens
   ============================================================================ */

/* Base adjustments */
html, body {
    font-size: 16px; /* slightly larger for readability */
}

/* Layout containers */
.container-fluid, .container {
    padding-left: 12px;
    padding-right: 12px;
}

/* ============================================================================
   MOBILE NAVIGATION: Drawer-Based (Hamburger + Sidebar)
   ============================================================================ */

@media (max-width: 768px) {
    /* Navbar adjustments for mobile: keep navbar visible but compact */
    .navbar {
        padding: 0.5rem 0;
        display: flex !important;
        flex-wrap: wrap;
    }

    .navbar-brand {
        font-size: 1.1rem;
        margin-right: auto;
    }

    /* Hide default navbar collapse on mobile - we use drawer instead */
    .navbar-collapse {
        display: none !important; /* Hidden by default on mobile */
        position: fixed;
        top: 70px; /* Height of navbar */
        left: 0;
        right: 0;
        bottom: 0;
        width: 100%;
        max-width: 280px; /* Drawer width */
        background: var(--sofatelcom-primary);
        flex-direction: column;
        padding: 1rem 0;
        overflow-y: auto;
        z-index: 999;
        box-shadow: 2px 0 8px rgba(0,0,0,0.15);
    }

    /* Show collapse when active (toggled by JS) */
    .navbar-collapse.show {
        display: flex !important;
    }

    /* Hamburger button always visible on mobile */
    .navbar-toggler {
        display: block !important;
        border: none;
        padding: 0.5rem 0.75rem;
        margin-left: 0.5rem;
    }

    .navbar-toggler:focus {
        box-shadow: 0 0 0 0.25rem rgba(255, 255, 255, 0.25);
    }

    /* Mobile nav items styling */
    .navbar-nav {
        width: 100%;
        flex-direction: column;
    }

    .navbar-nav .nav-item {
        width: 100%;
        border-bottom: 1px solid rgba(255, 255, 255, 0.1);
    }

    .navbar-nav .nav-link {
        padding: 0.75rem 1rem !important;
        color: #fff !important;
        border-left: 4px solid transparent;
        transition: all 0.2s ease;
    }

    .navbar-nav .nav-link:hover,
    .navbar-nav .nav-link.active {
        background-color: rgba(255, 255, 255, 0.15);
        border-left-color: #fff;
    }

    /* Dropdown menus in drawer - Critical fixes */
    .navbar-nav .dropdown-menu {
        position: static !important;
        background-color: rgba(0, 0, 0, 0.25) !important;
        border: none !important;
        box-shadow: none !important;
        margin: 0 !important;
        padding: 0 !important;
        border-radius: 0 !important;
        max-height: 0 !important;
        overflow: hidden !important;
        transition: max-height 0.3s ease-in-out !important;
        flex-direction: column !important;
        width: 100% !important;
        list-style: none !important;
    }

    /* CRITICAL: Show dropdown menu when toggled */
    .navbar-nav .dropdown-menu.show {
        max-height: 500px !important;
        overflow: visible !important;
        display: flex !important;
        visibility: visible !important;
    }

    .navbar-nav .dropdown-item {
        padding: 0.75rem 1rem 0.75rem 2rem !important;
        color: #fff !important;
        border-bottom: 1px solid rgba(255, 255, 255, 0.1) !important;
        background-color: transparent !important;
        white-space: normal !important;
        word-break: break-word !important;
        display: block !important;
        width: 100% !important;
        text-align: left !important;
        cursor: pointer !important;
        transition: background-color 0.15s ease !important;
    }

    .navbar-nav .dropdown-item:hover,
    .navbar-nav .dropdown-item:focus {
        background-color: rgba(255, 255, 255, 0.25) !important;
        color: #fff !important;
    }

    /* User/notification dropdowns - move to drawer for mobile */
    .navbar-nav:last-child {
        margin-top: auto;
        border-top: 1px solid rgba(255, 255, 255, 0.2);
    }

    /* Drawer overlay (backdrop) */
    .navbar-backdrop {
        position: fixed;
        top: 0;
        left: 0;
        right: 0;
        bottom: 0;
        background: rgba(0, 0, 0, 0.4);
        display: none;
        z-index: 998;
    }

    .navbar-backdrop.show {
        display: block;
    }

    /* Main content adjustment when drawer is open */
    body.drawer-open {
        overflow: hidden; /* Prevent body scroll */
    }

    /* Content area */
    main.container-fluid {
        padding-top: 1rem;
        padding-bottom: 1rem;
    }
}

/* Desktop: keep original navbar behavior */
@media (min-width: 769px) {
    .navbar-collapse {
        display: flex !important;
        position: static !important;
        width: auto !important;
        max-width: none !important;
        background: transparent !important;
        flex-direction: row !important;
        padding: 0 !important;
        overflow-y: visible !important;
        top: auto !important;
        box-shadow: none !important;
    }

    .navbar-toggler {
        display: none !important;
