    }

    .navbar-nav .nav-item {
        border-bottom: none !important;
    }

    .navbar-nav .nav-link {
        padding: 0.5rem 1rem !important;
        border-left: none !important;
    }

    .navbar-nav .dropdown-menu {
        position: absolute !important;
        background-color: white !important;
        border: 1px solid rgba(0, 0, 0, 0.1) !important;
        box-shadow: 0 0.5rem 1rem rgba(0, 0, 0, 0.15) !important;
        border-radius: 0.375rem !important;
    }

    .navbar-nav .dropdown-item {
        color: #212529 !important;
        padding: 0.5rem 1rem !important;
        border-bottom: none !important;
    }

    .navbar-nav .dropdown-item:hover {
        background-color: #f8f9fa !important;
    }
}

/* ============================================================================
   RESPONSIVE FORM & CONTENT ADJUSTMENTS
   ============================================================================ */

@media (max-width: 768px) {
    /* Increase tap targets */
    .btn, .form-control, .form-select {
        font-size: 1rem;
        padding: 10px 12px;
        min-height: 44px; /* Minimum touch target size */
    }

    /* Make cards and sections full width */
    .card, .intervention-section, .field-group {
        margin-left: 0;
        margin-right: 0;
        border-radius: 0.5rem;
    }

    /* Forms: stack labels above inputs */
    .form-label {
        display: block;
        margin-bottom: 6px;
        font-weight: 600;
    }

    /* Signature pad: full-width, taller on mobile */
    .signature-pad {
        height: 220px;
        touch-action: none;
    }

    /* Photo input: make button large and prominent */
    input[type="file"] {
        display: block;
        width: 100%;
    }

    /* Map: ensure it fits mobile screens */
    #map, .leaflet-container {
        height: 260px !important;
        width: 100% !important;
    }

    /* Tables: make scrollable */
    .table-responsive {
        overflow-x: auto;
    }

    /* Reduce margins to fit dense screens */
    .mb-4 { margin-bottom: 0.9rem !important; }
    .mt-3 { margin-top: 0.9rem !important; }

    /* Hide elements that are not useful on mobile */
    .sidebar, .breadcrumb, .big-legend { display: none !important; }

    /* Make alert notifications compact and fixed at top */
    .toast-alert { top: 8px; right: 8px; min-width: 240px; }
}

/* ============================================================================
