    width: auto;
    height: auto;
    padding: 8px 12px;
    background: var(--surface);
    color: var(--text);
    border-radius: 6px;
    box-shadow: var(--elevation-1);
    z-index: 1100;
}

/* Table header text color for contrast */
body.modern .table thead th { color: var(--text); }

/* Forms: modern inputs */
body.modern .form-control,
body.modern .form-select,
body.modern textarea.form-control {
    border-radius: 8px;
    border: 1px solid rgba(17,24,39,0.08);
    padding: 10px 12px;
    background: linear-gradient(180deg, #ffffff, #fbfbfb);
    box-shadow: inset 0 -1px 0 rgba(0,0,0,0.02);
    transition: box-shadow var(--transition-default), transform var(--transition-fast);
}

body.modern .form-control:focus,
body.modern .form-select:focus,
body.modern textarea.form-control:focus {
    border-color: var(--sofatelcom-secondary);
    box-shadow: 0 4px 18px rgba(13,110,253,0.06), 0 0 0 4px var(--focus-ring);
}

body.modern .is-invalid {
    border-color: rgba(220,53,69,0.9) !important;
}

body.modern .invalid-feedback {
    color: rgba(220,53,69,0.9);
    font-weight: 600;
}

/* Buttons: standardized sizes and shadows */
body.modern .btn-sofatelcom-primary {
    display: inline-flex;
    align-items: center;
    gap: .5rem;
}

body.modern .btn-outline-secondary {
    border-radius: 8px;
    padding: 8px 12px;
}

body.modern .btn-light {
    background: rgba(255,255,255,0.9);
    border: 1px solid rgba(17,24,39,0.04);
}

/* Table header elevation to make UI feel layered */
body.modern .table thead th {
    position: sticky;
    top: 0;
    z-index: 2;
    box-shadow: 0 6px 18px rgba(17,24,39,0.04);
}

/* Small utilities */
body.modern .page-header h1 { font-size: 26px; margin-bottom: 8px; }
body.modern .page-header p { color: var(--muted); margin-bottom: 0; }

/* Responsive tweaks */
@media (max-width: 768px) {
    body.modern .metric-value { font-size: 34px; }
    body.modern .kpi-hero { padding: 14px; }
}

/* Opt-out helper: keep legacy visuals by not setting body.modern */

/* Micro-interactions: subtle transitions and pressed state */
body.modern .pressed {
    transform: scale(0.99) !important;
    transition: transform 120ms ease;
}

/* Skeleton utility - used by macros (adds pulse while data-skeleton attribute present) */
[data-skeleton] .skeleton-card,
