/* Collapsible transition helper for Alpine-based panels */
.collapsible-body {
    transition: max-height 280ms cubic-bezier(.2,.8,.2,1), opacity 200ms ease;
    overflow: hidden;
}

/* Small micro-animations for icons on hover */
body.modern .icon-hover:hover {
    transform: translateY(-3px) scale(1.03);
    transition: transform 180ms ease;
}
