}

.table-controls .btn-outline-secondary:hover {
    color: var(--color-text-primary);
    border-color: var(--color-border);
    background-color: var(--color-bg-secondary);
}

/* État vide */
.responsive-table-container .alert {
    margin-bottom: 0;
}

/* Responsivité mobile */
@media (max-width: 768px) {
    .table-interactive {
        font-size: 0.8125rem;
    }

