    outline-offset: 2px;
}

/* Animations de ligne au chargement */
.table-interactive tbody tr {
    animation: rowFadeIn 300ms ease;
}

@keyframes rowFadeIn {
    from {
        opacity: 0;
        transform: translateY(-5px);
    }
    to {
        opacity: 1;
        transform: translateY(0);
    }
}

/* Affichage progressif avec délai */
.table-interactive tbody tr:nth-child(1) { animation-delay: 0ms; }
.table-interactive tbody tr:nth-child(2) { animation-delay: 30ms; }
.table-interactive tbody tr:nth-child(3) { animation-delay: 60ms; }
.table-interactive tbody tr:nth-child(n+4) { animation-delay: 90ms; }

/* Sélecteur pour animers les suppressions */
